#!/bin/sh
# Setup Super Admin - One Liner
# Execute este comando no console do container chatwell
# NOTA: Este arquivo é apenas referência. Use o comando documentado em MANUAL_MIGRATION.md

# Este script gera a senha automaticamente para segurança
node -e "const bcrypt=require('bcryptjs');const{Client}=require('pg');(async()=>{const c=new Client({connectionString:process.env.DATABASE_URL});try{await c.connect();console.log('Conectando...');await c.query('CREATE TABLE IF NOT EXISTS super_admins(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),username VARCHAR(100) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,name VARCHAR(255) NOT NULL,email VARCHAR(255) UNIQUE NOT NULL,is_active BOOLEAN DEFAULT true,last_login TIMESTAMP,created_at TIMESTAMP DEFAULT NOW(),updated_at TIMESTAMP DEFAULT NOW())');console.log('✓ Tabela');await c.query('CREATE INDEX IF NOT EXISTS idx_super_admins_username ON super_admins(username);CREATE INDEX IF NOT EXISTS idx_super_admins_email ON super_admins(email);CREATE INDEX IF NOT EXISTS idx_super_admins_active ON super_admins(is_active)');console.log('✓ Indices');const pwd=process.env.SUPER_ADMIN_PASSWORD||'ChangeMe@'+Math.random().toString(36).slice(2,8);const h=await bcrypt.hash(pwd,10);const r=await c.query('INSERT INTO super_admins(username,password_hash,name,email)VALUES(\$1,\$2,\$3,\$4)ON CONFLICT(username)DO NOTHING RETURNING id',['admin',h,'Super Administrador','admin@chatwell.com']);if(r.rows.length>0){console.log('\\n=====================\\nSUCESSO!\\n=====================\\nUsuario: admin\\nSenha: '+pwd+'\\n=====================\\n')}else{console.log('Ja existia')}await c.end();process.exit(0)}catch(e){console.error('Erro:',e.message);await c.end();process.exit(1)}})();"
